def make_channel(channel_id="c1", member_ids=("m1", "m2", "m3"), is_thread=False, parent=None):
    return Channel(id=channel_id, member_ids=set(member_ids), is_thread=is_thread, parent=parent)


def make_message(message_id="msg1", channel=None, author_id="m99", mentions=("m1",), kind=MentionKind.INDIVIDUAL):
    channel = channel or make_channel()
    return Message(id=message_id, channel=channel, author_id=author_id, mention_ids=list(mentions), mention_kind=kind)


def make_member(member_id="m1"):
    return Member(id=member_id)


