# ---------------------------------------------------------------------------

def test_edit_adding_new_mention_triggers_fresh_mention_pipeline():
    """REQ-005: edit adds @m2 → run REQ-001 pipeline for m2."""
    channel = make_channel("c1", member_ids=("m1", "m2", "m99"))
    old = make_message(channel=channel, author_id="m99", mentions=("m1",))
    new = make_message(channel=channel, author_id="m99", mentions=("m1", "m2"))

    push, banner, sound, badge = PushSurface(), InAppBannerSurface(), SoundSurface(), UnreadBadgeSurface()
    OnMessageEdited(old_message=old, new_message=new, surfaces=(push, banner, sound, badge))

    # m2 is the newly-added mention → all four surfaces should fire for m2.
    assert push.fire_count_for_member("m2") == 1
    assert banner.fire_count_for_member("m2") == 1
    assert sound.fire_count_for_member("m2") == 1
    assert badge.increment_count_for_member("m2") == 1
    # m1 was already mentioned — must NOT be re-dispatched.
    assert push.fire_count_for_member("m1") == 0


def test_edit_not_changing_mention_set_does_not_retrigger():
    """REQ-005 (negative): edit with same mention set → no re-dispatch."""
    channel = make_channel("c1", member_ids=("m1", "m99"))
    old = make_message(channel=channel, author_id="m99", mentions=("m1",))
    new = make_message(channel=channel, author_id="m99", mentions=("m1",))
    new.body = "edited but mentions unchanged"

    push = PushSurface()
    OnMessageEdited(old_message=old, new_message=new, surfaces=(push, InAppBannerSurface(), SoundSurface(), UnreadBadgeSurface()))

    assert push.total_fire_count() == 0


def test_edit_added_mention_to_non_member_is_silently_skipped():
    """REQ-005 + REQ-003: edit adds mention to non-channel-member → skip silently."""
    channel = make_channel("c1", member_ids=("m1", "m99"))  # m2 NOT a member
    old = make_message(channel=channel, author_id="m99", mentions=("m1",))
    new = make_message(channel=channel, author_id="m99", mentions=("m1", "m2"))

    push, banner, sound, badge = PushSurface(), InAppBannerSurface(), SoundSurface(), UnreadBadgeSurface()
    # Must not raise.
    OnMessageEdited(old_message=old, new_message=new, surfaces=(push, banner, sound, badge))

    assert push.fire_count_for_member("m2") == 0
    assert banner.fire_count_for_member("m2") == 0


