def test_delete_retracts_in_app_banner_for_unopened_notification():
    """REQ-006: delete unopened mention → in-app banner retracted."""
    channel = make_channel("c1", member_ids=("m1", "m99"))
    msg = make_message(channel=channel, author_id="m99", mentions=("m1",))
    push, banner, sound, badge = PushSurface(), InAppBannerSurface(), SoundSurface(), UnreadBadgeSurface()
    # First dispatch so there's something to retract.
    from src.notifications.models import MentionEvent
    from datetime import datetime, timezone
    event = MentionEvent(
        id="evt-msg1-m1", message_id="msg1", channel_id="c1",
        mentioner_id="m99", mentioned_id="m1", mention_kind=MentionKind.INDIVIDUAL,
        created_at=datetime(2026, 5, 24, 12, 0, tzinfo=timezone.utc),
    )
    DispatchMentionNotification(member=make_member("m1"), event=event, surfaces=(push, banner, sound, badge), dnd=None)

    OnMessageDeleted(message=msg, surfaces=(push, banner, sound, badge))

    assert banner.was_retracted_for(event)


def test_delete_leaves_push_unchanged():
    """REQ-006: push is non-retractable → leave as-is after delete."""
    channel = make_channel("c1", member_ids=("m1", "m99"))
    msg = make_message(channel=channel, author_id="m99", mentions=("m1",))
    push, banner, sound, badge = PushSurface(), InAppBannerSurface(), SoundSurface(), UnreadBadgeSurface()
    from src.notifications.models import MentionEvent
    from datetime import datetime, timezone
    event = MentionEvent(
        id="evt-msg1-m1", message_id="msg1", channel_id="c1",
        mentioner_id="m99", mentioned_id="m1", mention_kind=MentionKind.INDIVIDUAL,
        created_at=datetime(2026, 5, 24, 12, 0, tzinfo=timezone.utc),
    )
    DispatchMentionNotification(member=make_member("m1"), event=event, surfaces=(push, banner, sound, badge), dnd=None)

    before = push.fire_count_for(event)
    OnMessageDeleted(message=msg, surfaces=(push, banner, sound, badge))
    after = push.fire_count_for(event)

    assert before == after, "push was modified by delete — must be untouched"
    assert not push.was_retracted_for(event)


